import SwiftUI
import Combine
import UIKit

struct VitrineView: View {
    // --- PROPRIEDADES ---
    var ongs: [Ong]
    var carregando: Bool
    var onLoginClick: () -> Void
    var onOngClick: (Ong) -> Void
    var usuario: Usuario? = nil
    
    private var nomeExibicao: String {
        if let user = usuario {
            let primeiroNome = user.nome.components(separatedBy: " ").first ?? user.nome
            return "Olá, \(primeiroNome)"
        }
        return "Olá, Visitante 👋"
    }
    
    // --- ESTADOS ---
    @State private var selectedCategory: String = "Todos"
    @State private var searchQuery: String = ""
    
    let categories = ["Todos", "Saúde", "Animais", "Educação", "Ambiente", "Social"]
    
    // Paleta de Cores Premium
    let pageBackground = Color(red: 0.07, green: 0.10, blue: 0.17) // #121A2C
    let cardBg = Color(red: 0.12, green: 0.16, blue: 0.23)         // #1E293B
    let brandViolet = Color(red: 0.55, green: 0.36, blue: 0.96)    // #8B5CF6
    let brandMagenta = Color(red: 0.85, green: 0.27, blue: 0.94)   // #D946EF
    let brandOrange = Color(red: 0.96, green: 0.62, blue: 0.04)    // #F59E0B
    let txtGray = Color(red: 0.58, green: 0.64, blue: 0.72)        // #94A3B8

    // --- LÓGICA DE FILTRO ---
    var ongsFiltradas: [Ong] {
        ongs.filter { ong in
            let matchesCategory = selectedCategory == "Todos" || ong.causa.localizedCaseInsensitiveContains(selectedCategory)
            let search = searchQuery.trimmingCharacters(in: .whitespacesAndNewlines)
            let matchesSearch = search.isEmpty ||
                ong.nome.localizedCaseInsensitiveContains(search) ||
                ong.causa.localizedCaseInsensitiveContains(search) ||
                ong.descricao.localizedCaseInsensitiveContains(search)
            
            return matchesCategory && matchesSearch
        }
    }
    
    var body: some View {
        ZStack {
            pageBackground.ignoresSafeArea()
            
            ScrollView(showsIndicators: false) {
                VStack(spacing: 24) {
                    
                    // 1. CABEÇALHO (Logo e Avatar)
                    HStack {
                        VStack(alignment: .leading, spacing: 4) {
                            Text(nomeExibicao)
                                .font(.system(size: 24, weight: .bold))
                                .foregroundColor(.white)
                            Text("Conectando você a quem precisa")
                                .font(.system(size: 15))
                                .foregroundColor(txtGray)
                        }
                        .shimmer(isActive: carregando)
                        
                        Spacer()
                        
                        Button(action: onLoginClick) {
                            ZStack {
                                Circle()
                                    .fill(cardBg)
                                    .frame(width: 48, height: 48)
                                Image(systemName: "person.fill")
                                    .foregroundColor(brandViolet)
                                    .font(.system(size: 20))
                            }
                            .overlay(Circle().stroke(brandViolet.opacity(0.3), lineWidth: 1))
                        }
                    }
                    .padding(.horizontal, 24)
                    .padding(.top, 20)
                    
                    // 2. BARRA DE BUSCA
                    HStack(spacing: 12) {
                        Image(systemName: "magnifyingglass")
                            .foregroundColor(brandViolet)
                            .font(.system(size: 18, weight: .bold))
                        
                        TextField("", text: $searchQuery, prompt: Text("Buscar causa, ONG...").foregroundColor(txtGray.opacity(0.6)))
                            .foregroundColor(.white)
                            .font(.system(size: 16))
                            .autocapitalization(.none)
                            .disableAutocorrection(true)
                    }
                    .padding()
                    .background(cardBg)
                    .cornerRadius(16)
                    .overlay(RoundedRectangle(cornerRadius: 16).stroke(Color.white.opacity(0.05), lineWidth: 1))
                    .padding(.horizontal, 24)
                    
                    // 3. FILTROS (CHIPS)
                    ScrollView(.horizontal, showsIndicators: false) {
                        HStack(spacing: 12) {
                            ForEach(categories, id: \.self) { category in
                                let isSelected = category == selectedCategory
                                Text(category)
                                    .font(.system(size: 14, weight: isSelected ? .bold : .medium))
                                    .foregroundColor(isSelected ? .white : txtGray)
                                    .padding(.horizontal, 20)
                                    .padding(.vertical, 10)
                                    .background(isSelected ? brandViolet : cardBg)
                                    .clipShape(Capsule())
                                    .onTapGesture {
                                        if !carregando {
                                            withAnimation(.spring()) { selectedCategory = category }
                                        }
                                    }
                            }
                        }
                        .padding(.horizontal, 24)
                        .shimmer(isActive: carregando)
                    }
                    
                    // 4. CARROSSEL DE PARCEIROS (NOVO HERO CARD)
                    CarrosselParceirosView()
                        .shimmer(isActive: carregando)
                    
                    // 5. TÍTULO LISTA
                    HStack {
                        Text("Instituições Parceiras")
                            .font(.system(size: 18, weight: .bold))
                            .foregroundColor(.white)
                        Spacer()
                        if !carregando && !ongsFiltradas.isEmpty {
                            Text("\(ongsFiltradas.count) encontradas")
                                .font(.system(size: 12))
                                .foregroundColor(txtGray)
                        }
                    }
                    .padding(.horizontal, 24)
                    .shimmer(isActive: carregando)
                    
                    // 6. LISTA DE ONGS (SKELETON)
                    if carregando {
                        VStack(spacing: 16) {
                            ForEach(0..<3, id: \.self) { _ in
                                OngPremiumCard(ong: Ong(id: "", nome: "Carregando...", causa: "Geral", descricao: "Carregando informações da ONG...", imagem_url: "", cor: "#8B5CF6", cnpj: "")) { }
                                    .shimmer(isActive: true)
                            }
                        }
                        .padding(.horizontal, 24)
                    } else if ongsFiltradas.isEmpty {
                        VStack(spacing: 12) {
                            Image(systemName: "doc.text.magnifyingglass")
                                .font(.system(size: 40))
                                .foregroundColor(txtGray.opacity(0.5))
                            Text("Nenhuma ONG encontrada.")
                                .foregroundColor(txtGray)
                                .font(.system(size: 15))
                        }
                        .padding(40)
                        .frame(maxWidth: .infinity)
                        .background(cardBg.opacity(0.5))
                        .cornerRadius(20)
                        .padding(.horizontal, 24)
                    } else {
                        LazyVStack(spacing: 16) {
                            ForEach(ongsFiltradas) { ong in
                                OngPremiumCard(ong: ong) {
                                    onOngClick(ong)
                                }
                            }
                        }
                        .padding(.horizontal, 24)
                    }
                    
                    Spacer().frame(height: 30)
                }
            }
        }
    }
}

// MARK: - MODELO DE DADOS DOS PARCEIROS
struct Parceiro: Identifiable {
    let id = UUID()
    let nome: String
    let titulo: String
    let mensagem: String
    let logoBase64: String // Código Base64 da imagem da empresa
}

// MARK: - COMPONENTE DO CARROSSEL DE PARCEIROS
struct CarrosselParceirosView: View {
    // Insira os parceiros aqui. O segundo é o padrão do UNOS/Solidarizar.
    let parceiros: [Parceiro] = [
        Parceiro(nome: "Castanhas Ouro Verde",
                 titulo: "EMPRESA PARCEIRA",
                 mensagem: "Apoiando causas locais com o Solidarizar.",
                 logoBase64: """
                 

                 """
        ),
        Parceiro(nome: "Solidarizar",
                 titulo: "FAÇA A DIFERENÇA",
                 mensagem: "Sua doação chega direto ao destino.",
                 logoBase64: "solidarizar_padrao")
    ]
    
    @State private var currentIndex = 0
    let brandViolet = Color(red: 0.55, green: 0.36, blue: 0.96)
    let brandMagenta = Color(red: 0.85, green: 0.27, blue: 0.94)
    
    // Timer para o auto-scroll (5 segundos)
    let timer = Timer.publish(every: 5, on: .main, in: .common).autoconnect()

    var body: some View {
        TabView(selection: $currentIndex) {
            ForEach(0..<parceiros.count, id: \.self) { index in
                let parceiro = parceiros[index]
                
                ZStack(alignment: .leading) {
                    // Fundo Gradiente
                    LinearGradient(
                        colors: [brandViolet, brandMagenta],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    )
                    
                    // Ícone decorativo de fundo
                    Image(systemName: "heart.fill")
                        .font(.system(size: 140))
                        .foregroundColor(.white.opacity(0.08))
                        .offset(x: -30, y: 40)
                    
                    HStack(spacing: 15) {
                        // Textos da Esquerda
                        VStack(alignment: .leading, spacing: 10) {
                            Text(parceiro.titulo)
                                .font(.system(size: 10, weight: .bold))
                                .tracking(2)
                                .foregroundColor(.white.opacity(0.9))
                                .padding(.horizontal, 8)
                                .padding(.vertical, 4)
                                .background(Color.black.opacity(0.2))
                                .cornerRadius(6)
                            
                            Text(parceiro.nome)
                                .font(.system(size: 22, weight: .black))
                                .foregroundColor(.white)
                                .lineSpacing(-2)
                                .lineLimit(2)
                                .minimumScaleFactor(0.8)
                            
                            Text(parceiro.mensagem)
                                .font(.system(size: 12))
                                .foregroundColor(.white.opacity(0.8))
                                .lineLimit(2)
                            
                            Spacer().frame(height: 2)
                        }
                        
                        Spacer()
                        
                        // MOLDURA BRANCA PARA A LOGO
                                                ZStack {
                                                    Circle()
                                                        .fill(Color.white)
                                                        .frame(width: 85, height: 85)
                                                        .shadow(color: .black.opacity(0.15), radius: 10, x: 0, y: 5)
                                                    
                                                    // Lógica blindada para renderizar o Base64
                                                    let base64Limpo = parceiro.logoBase64
                                                        .components(separatedBy: ",").last?
                                                        .replacingOccurrences(of: "\n", with: "")
                                                        .replacingOccurrences(of: "\r", with: "")
                                                        .replacingOccurrences(of: " ", with: "") ?? ""
                                                    
                                                    if let data = Data(base64Encoded: base64Limpo, options: .ignoreUnknownCharacters),
                                                       let uiImage = UIImage(data: data) {
                                                        Image(uiImage: uiImage)
                                                            .resizable()
                                                            .scaledToFit()
                                                            // 👇 NOVA LINHA: Adicionamos padding interno para afastar o conteúdo da borda do círculo de corte
                                                            .padding(8)
                                                            // 👆 FIM DA NOVA LINHA
                                                            .frame(width: 60, height: 60)
                                                            .clipShape(Circle())
                                                    } else {
                                                        // Fallback: se não tiver base64 válido
                                                        Image(systemName: "building.2.fill")
                                                            .font(.system(size: 30))
                                                            .foregroundColor(brandViolet.opacity(0.5))
                                                    }
                                                }
                    }
                    .padding(24)
                }
                .frame(maxWidth: .infinity)
                .frame(height: 200)
                .cornerRadius(24)
                .shadow(color: brandViolet.opacity(0.3), radius: 15, x: 0, y: 10)
                .padding(.horizontal, 24)
                .tag(index)
            }
        }
        .frame(height: 200)
        .tabViewStyle(PageTabViewStyle(indexDisplayMode: .always))
        .onReceive(timer) { _ in
            withAnimation(.spring()) {
                currentIndex = currentIndex < parceiros.count - 1 ? currentIndex + 1 : 0
            }
        }
    }
}

// MARK: - CARD DA ONG PREMIUM
struct OngPremiumCard: View {
    let ong: Ong
    let onClick: () -> Void
    
    var accentColor: Color {
        if !ong.cor.isEmpty { return Color(hex: ong.cor) }
        return Color(red: 0.55, green: 0.36, blue: 0.96)
    }
    
    var body: some View {
        Button(action: onClick) {
            HStack(spacing: 16) {
                // Logo da ONG
                if let base64String = ong.imagem_url.components(separatedBy: ",").last,
                   let data = Data(base64Encoded: base64String),
                   let uiImage = UIImage(data: data) {
                    Image(uiImage: uiImage)
                        .resizable()
                        .scaledToFill()
                        .frame(width: 60, height: 60)
                        .clipShape(RoundedRectangle(cornerRadius: 12))
                } else {
                    ZStack {
                        RoundedRectangle(cornerRadius: 12).fill(accentColor.opacity(0.1))
                        Image(systemName: "heart.text.square.fill")
                            .foregroundColor(accentColor)
                            .font(.system(size: 24))
                    }
                    .frame(width: 60, height: 60)
                }
                
                VStack(alignment: .leading, spacing: 4) {
                    Text(ong.causa.uppercased())
                        .font(.system(size: 10, weight: .bold))
                        .foregroundColor(accentColor)
                        .tracking(1)
                    
                    Text(ong.nome)
                        .font(.system(size: 17, weight: .bold))
                        .foregroundColor(.white)
                    
                    Text(ong.descricao)
                        .font(.system(size: 13))
                        .foregroundColor(Color(red: 0.58, green: 0.64, blue: 0.72))
                        .lineLimit(1)
                }
                
                Spacer()
                
                Image(systemName: "chevron.right")
                    .font(.system(size: 14, weight: .bold))
                    .foregroundColor(Color.white.opacity(0.3))
            }
            .padding(16)
            .background(Color(red: 0.12, green: 0.16, blue: 0.23))
            .cornerRadius(18)
            .overlay(
                RoundedRectangle(cornerRadius: 18)
                    .stroke(Color.white.opacity(0.05), lineWidth: 1)
            )
        }
        .buttonStyle(PlainButtonStyle())
    }
}
